public static ArrayList<Integer> next_permutation(ArrayList<Integer> perm) {
    //find largest index k such that perm[k] < perm[k+1]
    int k = perm.size() - 2;
    while(k >= 0 && perm.get(k) >= perm.get(k + 1)) {
        k--;
    }
    if(k == -1) return new ArrayList<Integer>();
    //find largest index l such that perm[k] < perm[l]
    int l = perm.size() - 1;
    while(l >= 0 && perm.get(k) >= perm.get(l)) {
        l--;
    }
    //swap perm[k] and perm[l]
    int temp = perm.get(k);
    perm.set(k, perm.get(l));
    perm.set(l, temp);
    //reverse perm[k+1:]
    Collections.reverse(perm.subList(k + 1, perm.size()));
    return perm;
}

public static ArrayList<Integer> next_permutation(ArrayList<Integer> perm) {
    // Find the largest index k such that perm[k] < perm[k + 1]. If no such index exists, the permutation is the last permutation.
    int k = -1;
    for (int i = 0; i < perm.size() - 1; i++) {
        if (perm.get(i) < perm.get(i + 1)) {
            k = i;
        }
    }
    if (k == -1) {
        return new ArrayList<Integer>();
    }

    // Find the largest index l greater than k such that perm[k] < perm[l].
    int l = -1;
    for (int i = k + 1; i < perm.size(); i++) {
        if (perm.get(k) < perm.get(i)) {
            l = i;
        }
    }

    // Swap the value of perm[k] with that of perm[l].
    int temp = perm.get(k);
    perm.set(k, perm.get(l));
    perm.set(l, temp);

    // Reverse the sequence from perm[k + 1] up to and including the final element perm[perm.length - 1].
    int i = k + 1;
    int j = perm.size() - 1;
    while (i < j) {
        temp = perm.get(i);
        perm.set(i, perm.get(j));
        perm.set(j, temp);
        i++;
        j--;
    }

    return perm;
}

